return [
  { json: { project_id: 1, name: '64 Eastwood', code: '64EW' } },
  { json: { project_id: 2, name: '101 Francis', code: '101F' } },
  { json: { project_id: 3, name: '1355 Riverside', code: '1355R' } }
];

const d = $input.first().json;
const h = d.health || 'GREEN';
const emoji = h === 'RED' ? '🔴' : h === 'YELLOW' ? '🟡' : '🟢';
const budget = d.budget || {};
const rfis = d.rfis || {};
const approvals = d.approvals || {};
const priorities = (d.next_week_priorities || []).slice(0, 3);

const title = `${emoji} ${d.project_code || ''} PM Week — ${d.week_of || ''}`;
const body = [
  `${h} — ${d.project_name}`,
  `Budget exposure: $${Math.round((budget.exposure || 0) / 1000)}k`,
  `Open RFIs: ${rfis.open_count || 0} (${rfis.overdue_count || 0} overdue)`,
  `Decisions pending: ${approvals.pending_count || 0}`,
  `---`,
  ...priorities.map((p, i) => `${i+1}. ${p}`),
  `View: http://localhost:8000/pm/${d.project_id}`
].join('\n');

const priority = h === 'RED' ? 'high' : (approvals.pending_count || 0) > 0 ? 'default' : 'low';

return [{ json: { title, body, priority } }];
